#include <iostream>
#include <vector>
using namespace std;

int main() {
  vector<string> names;

  names.push_back("Alice");
  names.push_back("Bob");
  names.push_back("Charlie");

  cout << "Size: " << names.size() << endl;
  cout << "First: " << names[0] << endl;

  for (const string& name : names) {
    cout << name << " ";
  }
  return 0;
}
